import {
  createContext,
  PropsWithChildren,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from "react";
import type { Session, User } from "@supabase/supabase-js";
import { supabase } from "@/lib/supabase";

type OwnerAuthContextValue = {
  session: Session | null;
  user: User | null;
  isOwner: boolean;
  initializing: boolean;
  signingIn: boolean;
  signInOwner: (email: string, password: string) => Promise<void>;
  signOutOwner: () => Promise<void>;
};

const OwnerAuthContext = createContext<OwnerAuthContextValue | undefined>(
  undefined
);

const OWNER_EMAILS = (
  process.env.EXPO_PUBLIC_OWNER_EMAILS ?? ""
)
  .split(",")
  .map((email) => email.trim().toLowerCase())
  .filter(Boolean);

export function OwnerAuthProvider({ children }: PropsWithChildren) {
  const [session, setSession] = useState<Session | null>(null);
  const [isOwner, setIsOwner] = useState(false);
  const [initializing, setInitializing] = useState(true);
  const [signingIn, setSigningIn] = useState(false);

  const verifyOwner = useCallback(async (candidate: Session | null) => {
    if (!candidate?.user) {
      setSession(null);
      setIsOwner(false);
      return false;
    }

    const email = candidate.user.email?.trim().toLowerCase();

    if (!email || !OWNER_EMAILS.includes(email)) {
      await supabase.auth.signOut({ scope: "local" });
      setSession(null);
      setIsOwner(false);
      throw new Error("This account is not authorized as an IVX owner.");
    }

    /*
     * Required enterprise verification:
     * Verify the owner role from the database, not only from the UI.
     *
     * Recommended table:
     * profiles:
     *   id uuid references auth.users(id)
     *   role text
     *   active boolean
     */

    const { data: profile, error } = await supabase
      .from("profiles")
      .select("id, role, active")
      .eq("id", candidate.user.id)
      .maybeSingle();

    if (error) {
      await supabase.auth.signOut({ scope: "local" });
      throw new Error(`Owner authorization check failed: ${error.message}`);
    }

    if (!profile || profile.role !== "owner" || profile.active !== true) {
      await supabase.auth.signOut({ scope: "local" });
      setSession(null);
      setIsOwner(false);
      throw new Error("Owner access is not active for this account.");
    }

    setSession(candidate);
    setIsOwner(true);
    return true;
  }, []);

  useEffect(() => {
    let mounted = true;

    const initialize = async () => {
      try {
        /*
         * Mandatory behavior:
         * Clear any old session left by previous versions of the app.
         */
        await supabase.auth.signOut({ scope: "local" });

        if (mounted) {
          setSession(null);
          setIsOwner(false);
        }
      } catch (error) {
        console.error("[OWNER_AUTH_INITIALIZATION]", error);

        if (mounted) {
          setSession(null);
          setIsOwner(false);
        }
      } finally {
        if (mounted) {
          setInitializing(false);
        }
      }
    };

    initialize();

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((event, nextSession) => {
      if (!mounted) return;

      if (event === "SIGNED_OUT") {
        setSession(null);
        setIsOwner(false);
      }

      /*
       * Do not automatically accept INITIAL_SESSION.
       * Only SIGNED_IN after manual credentials are submitted.
       */
      if (event === "SIGNED_IN" && nextSession) {
        void verifyOwner(nextSession).catch((error) => {
          console.error("[OWNER_ROLE_VERIFICATION]", error);
        });
      }
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, [verifyOwner]);

  const signInOwner = useCallback(
    async (email: string, password: string) => {
      const normalizedEmail = email.trim().toLowerCase();

      if (!normalizedEmail || !password) {
        throw new Error("Owner email and password are required.");
      }

      setSigningIn(true);

      try {
        // Ensure no old identity remains before attempting owner login.
        await supabase.auth.signOut({ scope: "local" });

        const { data, error } = await supabase.auth.signInWithPassword({
          email: normalizedEmail,
          password,
        });

        if (error) {
          throw new Error(error.message);
        }

        if (!data.session) {
          throw new Error("Supabase did not return an authenticated session.");
        }

        await verifyOwner(data.session);
      } catch (error) {
        setSession(null);
        setIsOwner(false);

        await supabase.auth.signOut({ scope: "local" }).catch(() => undefined);

        throw error;
      } finally {
        setSigningIn(false);
      }
    },
    [verifyOwner]
  );

  const signOutOwner = useCallback(async () => {
    const { error } = await supabase.auth.signOut({ scope: "local" });

    setSession(null);
    setIsOwner(false);

    if (error) {
      throw new Error(error.message);
    }
  }, []);

  const value = useMemo(
    () => ({
      session,
      user: session?.user ?? null,
      isOwner,
      initializing,
      signingIn,
      signInOwner,
      signOutOwner,
    }),
    [
      session,
      isOwner,
      initializing,
      signingIn,
      signInOwner,
      signOutOwner,
    ]
  );

  return (
    <OwnerAuthContext.Provider value={value}>
      {children}
    </OwnerAuthContext.Provider>
  );
}

export function useOwnerAuth() {
  const context = useContext(OwnerAuthContext);

  if (!context) {
    throw new Error(
      "useOwnerAuth must be used inside OwnerAuthProvider"
    );
  }

  return context;
}
